def epley_e1rm(load, reps):
    return load * (1 + reps / 30)


def get_last_session_data(db_path):
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()

    cur.execute("SELECT id, date, bodyweight FROM sessions ORDER BY date DESC LIMIT 1")
    session = cur.fetchone()
    if not session:
        conn.close()
        raise ValueError("No sessions found.")

    session_id = session["id"]
    date_raw = session["date"]
    bodyweight = session["bodyweight"]

    try:
        date_fmt = datetime.strptime(date_raw, "%Y-%m-%d").strftime("%B %d, %Y").upper()
    except Exception:
        date_fmt = str(date_raw).upper()

    cur.execute("""
        SELECT SUM(s.reps * s.load) as tonnage
        FROM sets s JOIN exercises e ON s.exercise_id = e.id
        WHERE e.session_id = ?
    """, (session_id,))
    tonnage = round((cur.fetchone()["tonnage"] or 0))

    cur.execute("""
        SELECT e.name, s.load, s.reps
        FROM sets s JOIN exercises e ON s.exercise_id = e.id
        WHERE e.session_id = ? AND s.load > 0 AND s.reps > 0
    """, (session_id,))
    all_sets = cur.fetchall()
    conn.close()

    def fmt(n):
        return int(n) if isinstance(n, float) and n == int(n) else n

    top_load_row = max(all_sets, key=lambda r: r["load"], default=None)
    top_vol_row = max(all_sets, key=lambda r: r["load"] * r["reps"], default=None)

    if top_load_row:
        top_exercise = top_load_row["name"].upper()
        top_set_str = f"{fmt(top_load_row['load'])} lbs × {top_load_row['reps']}"
        peak_load = fmt(top_load_row["load"])
    else:
        top_exercise = "N/A"
        top_set_str = "—"
        peak_load = "—"

    top_vol_str = f"{top_vol_row['name'].upper()}  {fmt(top_vol_row['load'])} × {top_vol_row['reps']}" if top_vol_row else "—"
    bw_fmt = fmt(bodyweight) if bodyweight else "—"

    summary_data = {
        "session_id": session_id,
        "date": date_fmt,
        "bodyweight": bw_fmt,
        "top_set_exercise": top_exercise,
        "top_set": top_set_str,
        "peak_load": peak_load,
        "top_vol": top_vol_str,
        "tonnage": f"{tonnage:,}",
    }
    summary = generate_session_summary(summary_data)

    return {
        "session_id": session_id,
        "date": date_fmt,
        "bodyweight": str(bw_fmt),
        "top_exercise": top_exercise,
        "top_set": top_set_str,
        "peak_load": str(peak_load),
        "tonnage": f"{tonnage:,}",
        "top_vol": top_vol_str,
        "summary": summary,
    }


def get_background_base64(context: dict = None):
    from assets.backgrounds.loader import pick_background_for_session, pick_background
    if context:
        chosen = pick_background_for_session(context)
    else:
        chosen = pick_background()
    if not chosen:
        return ""
    with open(chosen, "rb") as f:
        return base64.b64encode(f.read()).decode("utf-8")


